import glob, re, os

# 收集所有 wiki-link 目标
link_re = re.compile(r'\[\[([^]|]+?)(?:\|[^]]*)?\]\]')
targets = set()
for path in glob.glob('wiki/**/*.md', recursive=True):
    with open(path, encoding='utf-8') as f:
        for m in link_re.finditer(f.read()):
            targets.add(m.group(1).strip())

# 已知占位符(in CLAUDE.md examples) — 不检查
placeholders = {'name', 'wiki/entities/name.md', 'Clippings/slug.md'}

broken = []
for t in sorted(targets):
    if t in placeholders or not t.endswith('.md'):
        continue
    if not os.path.isfile(t):
        broken.append(t)

if broken:
    print("BROKEN LINKS:")
    for b in broken:
        print(f"  {b}")
else:
    print("✓ 全部 wiki-link 目标都解析到实际文件")

print(f"\n总链接目标数: {len(targets)}")
EOF

